{
  "name": "FAQ Cabinet Médical Saint-Martin",
  "description": "Questions fréquentes des patients : horaires, parking, accessibilité, motifs de consultation",
  "projectId": "{{projectId}}"
}

{
  "assistantId": "{{assistantId}}",
  "definitionId": "{{transferToolDefinitionId}}",
  "configuration": {
    "transfers": [
      {
        "destination": "{{transferNumber}}",
        "condition": "L'appelant demande explicitement à parler à un agent humain, un médecin, ou une personne réelle",
        "preTransferSentence": "Je vous transfère immédiatement vers notre secrétariat. Un instant s'il vous plaît."
      }
    ]
  },
  "projectId": "{{projectId}}"
}

{
  "name": "Medical appointment booking",
  "description": "Serveur MCP mock pour la prise de rendez-vous médicaux.",
  "url": "{{mcpUrl}}",
  "headers": {
    "Authorization": "Bearer {{mcpToken}}"
  },
  "projectId": "{{projectId}}"
}

{
  "name": "Évaluation post-conversation",
  "description": "Analyse automatique de la qualité des conversations par 3 agents LLM en parallèle",
  "steps": [
    {
      "type": "batch",
      "output": "evaluation",
      "config": {
        "mode": "all",
        "steps": [
          {
            "type": "agent",
            "output": "quality_analysis",
            "config": {
              "provider": "openai",
              "model": "gpt-4.1",
              "temperature": 0.2,
              "systemPrompt": "Tu es un expert en qualité de service client. Analyse la conversation fournie et évalue la qualité de l'interaction de l'assistant vocal.",
              "input": "Voici le transcript de la conversation :\n\n<< messages.map(m => m.from + ': ' + m.message).join('\\n') >>",
              "outputSchema": {
                "type": "object",
                "properties": {
                  "tone_score": {
                    "type": "number",
                    "description": "Score de qualité du ton (0-10)"
                  },
                  "clarity_score": {
                    "type": "number",
                    "description": "Score de clarté des réponses (0-10)"
                  },
                  "fluidity_score": {
                    "type": "number",
                    "description": "Score de fluidité de la conversation (0-10)"
                  },
                  "overall_score": {
                    "type": "number",
                    "description": "Score global de qualité (0-10)"
                  },
                  "strengths": {
                    "type": "array",
                    "items": { "type": "string" },
                    "description": "Points forts de la conversation"
                  },
                  "improvements": {
                    "type": "array",
                    "items": { "type": "string" },
                    "description": "Axes d'amélioration"
                  }
                },
                "required": ["tone_score", "clarity_score", "fluidity_score", "overall_score", "strengths", "improvements"]
              }
            }
          },
          {
            "type": "agent",
            "output": "resolution_analysis",
            "config": {
              "provider": "openai",
              "model": "gpt-4.1",
              "temperature": 0.2,
              "systemPrompt": "Tu es un analyste de résolution de demandes client. Détermine si le besoin de l'appelant a été satisfait pendant la conversation.",
              "input": "Voici le transcript de la conversation :\n\n<< messages.map(m => m.from + ': ' + m.message).join('\\n') >>\n\nVoici les events (appels d'outils) :\n\n<< JSON.stringify(events, null, 2) >>",
              "outputSchema": {
                "type": "object",
                "properties": {
                  "caller_intent": {
                    "type": "string",
                    "description": "L'intention principale de l'appelant"
                  },
                  "resolution_status": {
                    "type": "string",
                    "enum": ["resolved", "partially_resolved", "unresolved", "transferred"],
                    "description": "Statut de résolution de la demande"
                  },
                  "tools_used": {
                    "type": "array",
                    "items": { "type": "string" },
                    "description": "Liste des outils utilisés pendant la conversation"
                  },
                  "resolution_details": {
                    "type": "string",
                    "description": "Détail de comment la demande a été traitée"
                  }
                },
                "required": ["caller_intent", "resolution_status", "tools_used", "resolution_details"]
              }
            }
          },
          {
            "type": "agent",
            "output": "summary",
            "config": {
              "provider": "openai",
              "model": "gpt-4.1",
              "temperature": 0.3,
              "systemPrompt": "Tu es un rédacteur de comptes-rendus d'appels. Produis un résumé structuré et concis de la conversation.",
              "input": "Voici le transcript de la conversation :\n\n<< messages.map(m => m.from + ': ' + m.message).join('\\n') >>",
              "outputSchema": {
                "type": "object",
                "properties": {
                  "title": {
                    "type": "string",
                    "description": "Titre court de la conversation (max 10 mots)"
                  },
                  "summary": {
                    "type": "string",
                    "description": "Résumé de la conversation en 2-3 phrases"
                  },
                  "action_items": {
                    "type": "array",
                    "items": { "type": "string" },
                    "description": "Actions à suivre après la conversation"
                  },
                  "tags": {
                    "type": "array",
                    "items": { "type": "string" },
                    "description": "Tags de catégorisation (ex: faq, rdv, transfer, urgence)"
                  }
                },
                "required": ["title", "summary", "action_items", "tags"]
              }
            }
          }
        ]
      }
    },
    {
      "type": "request",
      "output": "webhook_result",
      "config": {
        "url": "https://ad-webinar-backend.eu.ngrok.io/api/webhook/evaluation",
        "method": "POST",
        "headers": {
          "Content-Type": "application/json"
        },
        "data": {
          "exchangeId": "{{ id }}",
          "assistantId": "{{ assistantId }}",
          "quality": "<< evaluation.quality_analysis.output >>",
          "resolution": "<< evaluation.resolution_analysis.output >>",
          "summary": "<< evaluation.summary.output >>"
        }
      }
    },
    {
      "type": "email",
      "output": "email_result",
      "config": {
        "to": "antoine@reecall.co",
        "from": "noreply@reecall.co",
        "fromName": "Reecall - Évaluation Automatique",
        "subject": "Rapport d'évaluation - {{ evaluation.summary.output.title }}",
        "htmlPart": "<h1>Rapport d'évaluation de conversation</h1><h2>Résumé</h2><p>{{ evaluation.summary.output.summary }}</p><h2>Qualité ({{ evaluation.quality_analysis.output.overall_score }}/10)</h2><p><strong>Ton :</strong> {{ evaluation.quality_analysis.output.tone_score }}/10<br/><strong>Clarté :</strong> {{ evaluation.quality_analysis.output.clarity_score }}/10<br/><strong>Fluidité :</strong> {{ evaluation.quality_analysis.output.fluidity_score }}/10</p><h2>Résolution</h2><p><strong>Intent :</strong> {{ evaluation.resolution_analysis.output.caller_intent }}<br/><strong>Statut :</strong> {{ evaluation.resolution_analysis.output.resolution_status }}</p><p>{{ evaluation.resolution_analysis.output.resolution_details }}</p>"
      }
    }
  ],
  "projectId": "{{projectId}}"
}

{
  "blueprint": {
    "models": [
      {
        "name": "KB",
        "model": "ai.KnowledgeBase",
        "template": {
          "name": "FAQ {{ clientName }}",
          "description": "Questions fréquentes des patients : horaires, parking, accessibilité, motifs de consultation",
          "projectId": "{{ projectId }}"
        }
      },
      {
        "name": "KNOWLEDGE_HORAIRES",
        "model": "ai.Knowledge",
        "template": {
          "title": "Horaires d'ouverture",
          "content": "Le cabinet est ouvert du lundi au vendredi de 8h30 à 12h30 et de 14h00 à 18h30. Le samedi matin de 9h00 à 12h00 sur rendez-vous uniquement. Le cabinet est fermé le dimanche et les jours fériés.",
          "knowledgeBaseId": "{{ blueprint.KB }}",
          "available": true,
          "projectId": "{{ projectId }}"
        }
      },
      {
        "name": "KNOWLEDGE_PARKING",
        "model": "ai.Knowledge",
        "template": {
          "title": "Parking et accès véhicule",
          "content": "Un parking gratuit de 20 places est disponible devant le cabinet, accessible par la rue des Lilas. Deux places sont réservées aux personnes à mobilité réduite. Un dépose-minute est situé juste devant l'entrée principale.",
          "knowledgeBaseId": "{{ blueprint.KB }}",
          "available": true,
          "projectId": "{{ projectId }}"
        }
      },
      {
        "name": "KNOWLEDGE_ACCESSIBILITE",
        "model": "ai.Knowledge",
        "template": {
          "title": "Accessibilité personnes à mobilité réduites",
          "content": "Le cabinet est entièrement accessible aux personnes à mobilité réduite. L'entrée principale est de plain-pied avec une rampe d'accès. Un ascenseur dessert tous les étages. Les sanitaires sont adaptés PMR au rez-de-chaussée.",
          "knowledgeBaseId": "{{ blueprint.KB }}",
          "available": true,
          "projectId": "{{ projectId }}"
        }
      },
      {
        "name": "KNOWLEDGE_MOTIFS",
        "model": "ai.Knowledge",
        "template": {
          "title": "Motifs de consultation acceptés pour la prise de RDV",
          "content": "Les motifs de consultation disponibles à la prise de RDV sont : consultation générale, renouvellement d'ordonnance, vaccination, certificat médical, suivi de pathologie chronique, consultation d'urgence (sous réserve de disponibilité).",
          "knowledgeBaseId": "{{ blueprint.KB }}",
          "available": true,
          "projectId": "{{ projectId }}"
        }
      },
      {
        "name": "MCP",
        "model": "ai.Mcp",
        "template": {
          "name": "{{ mcpName }}",
          "description": "Serveur MCP mock pour la prise de rendez-vous médicaux.",
          "url": "{{ mcpUrl }}",
          "headers": {{ headers }},
          "projectId": "{{ projectId }}"
        }
      },
      {
        "name": "ASSISTANT",
        "model": "conversational.Assistant",
        "template": {
          "name": "{{ assistantName }}",
          "instructions": "# Identité\nTu es l'assistant vocal du {{ clientName }}. Tu réponds aux appels téléphoniques des patients.\n# Règle absolue — Interdiction d'inventer\nTu ne dois JAMAIS inventer, supposer, déduire ou extrapoler une information qui n'est pas explicitement écrite dans ce prompt. Si la question du patient porte sur un sujet non couvert ci-dessus, tu dois répondre :\n« Veuillez m'excuser, je n'ai pas cette information. »\nCette règle est prioritaire sur toutes les autres. En cas de doute, applique cette règle.\n# Tâches\n1. **Répondre aux questions fréquentes** en utilisant UNIQUEMENT les informations présentent dans ce prompt.\n2. **Aider à la prise de rendez-vous** :\n   - Demande le motif de consultation\n   - Demande la préférence de créneau (jour, matin/après-midi)\n   - Utilise ensuite l'outil de prise de rendez-vous\n3. **Transférer vers un agent humain** si le patient le demande explicitement, ou si la situation dépasse tes capacités.\n# Ton et style\n- Poli, professionnel, rassurant\n- Phrases courtes et claires (contexte téléphonique)\n- Vouvoiement systématique\n- Pas de jargon médical inutile\n# Interdictions\n- Ne jamais donner de conseil médical, de diagnostic ou d'avis thérapeutique\n- Ne jamais confirmer ou infirmer un diagnostic\n- Ne jamais communiquer d'information personnelle sur un médecin ou un patient\n- Ne jamais inventer une information (voir règle absolue ci-dessus)",
          "language": "fr-FR",
          "timezone": "Europe/Paris",
          "temperature": 0.3,
          "stsId": "{{ stsId }}",
          "voiceId": "{{ voiceId }}",
          "firstMessage": "Bonjour, bienvenue au {{ clientName }}. Comment puis-je vous aider ?",
          "knowledgeBaseIds": ["{{ blueprint.KB }}"],
          "mcpIds": ["{{ blueprint.MCP }}"],
          "projectId": "{{ projectId }}"
        }
      },
      {
        "name": "TRANSFER_TOOL",
        "model": "ai.Tool",
        "template": {
          "assistantId": "{{ blueprint.ASSISTANT }}",
          "definitionId": "{{ transferToolDefinitionId }}",
          "configuration": {
            "transfers": [
              {
                "destination": "{{ transferNumber }}",
                "condition": "L'appelant demande explicitement à parler à un agent humain, un médecin, ou une personne réelle",
                "preTransferSentence": "Je vous transfère immédiatement vers notre secrétariat. Un instant s'il vous plaît."
              }
            ]
          },
          "projectId": "{{ projectId }}"
        }
      },
      {
        "name": "CHANNEL",
        "model": "conversational.Channel",
        "template": {
          "name": "{{ channelName }}",
          "type": "WEBRTC",
          "assistantId": "{{ blueprint.ASSISTANT }}",
          "projectId": "{{ projectId }}"
        }
      }
    ],
    "overrides": {}
  },
  "context": {
    "clientName": "Cabinet Médical Saint-Martin",
    "assistantName": "Assistant Cabinet Médical - Webinar Demo",
    "channelName": "Medical Channel - Webinar Demo",
    "mcpName": "Medical appointment booking",
    "stsId": "{{stsId}}",
    "voiceId": "{{voiceId}}",
    "mcpUrl": "{{mcpUrl}}",
    "headers": {
      "Authorization": "Bearer {{mcpToken}}"
    },
    "projectId": "{{projectId}}",
    "endConversationToolDefinitionId": "{{endConversationToolDefinitionId}}",
    "transferToolDefinitionId": "{{transferToolDefinitionId}}",
    "transferNumber": "{{transferNumber}}"
  }
}
